$env_node_path=$env:NODE_PATH
$new_node_path="C:\Users\ryahj\CascadeProjects\serviosapp\Servios\node_modules\.pnpm\semantic-release@22.0.12_typescript@5.8.3\node_modules\semantic-release\bin\node_modules;C:\Users\ryahj\CascadeProjects\serviosapp\Servios\node_modules\.pnpm\semantic-release@22.0.12_typescript@5.8.3\node_modules\semantic-release\node_modules;C:\Users\ryahj\CascadeProjects\serviosapp\Servios\node_modules\.pnpm\semantic-release@22.0.12_typescript@5.8.3\node_modules;C:\Users\ryahj\CascadeProjects\serviosapp\Servios\node_modules\.pnpm\node_modules"
if ($PSVersionTable.PSVersion -lt "6.0" -or $IsWindows) {
  # Fix case when both the Windows and Linux builds of Node
  # are installed in the same directory
  $exe=".exe"
  $pathsep=";"
} else {
  $new_node_path="/mnt/c/Users/ryahj/CascadeProjects/serviosapp/Servios/node_modules/.pnpm/semantic-release@22.0.12_typescript@5.8.3/node_modules/semantic-release/bin/node_modules:/mnt/c/Users/ryahj/CascadeProjects/serviosapp/Servios/node_modules/.pnpm/semantic-release@22.0.12_typescript@5.8.3/node_modules/semantic-release/node_modules:/mnt/c/Users/ryahj/CascadeProjects/serviosapp/Servios/node_modules/.pnpm/semantic-release@22.0.12_typescript@5.8.3/node_modules:/mnt/c/Users/ryahj/CascadeProjects/serviosapp/Servios/node_modules/.pnpm/node_modules"
}
if ([string]::IsNullOrEmpty($env_node_path)) {
  $env:NODE_PATH=$new_node_path
} else {
