}

$ret=0
if (Test-Path "$basedir/node$exe") {
  # Support pipeline input
  if ($MyInvocation.ExpectingInput) {
    $input | & "$basedir/node$exe"  "$basedir/../../../../../../semantic-release@22.0.12_typescript@5.8.3/node_modules/semantic-release/bin/semantic-release.js" $args
  } else {
    & "$basedir/node$exe"  "$basedir/../../../../../../semantic-release@22.0.12_typescript@5.8.3/node_modules/semantic-release/bin/semantic-release.js" $args
  }
  $ret=$LASTEXITCODE
} else {
  # Support pipeline input
  if ($MyInvocation.ExpectingInput) {
    $input | & "node$exe"  "$basedir/../../../../../../semantic-release@22.0.12_typescript@5.8.3/node_modules/semantic-release/bin/semantic-release.js" $args
  } else {
    & "node$exe"  "$basedir/../../../../../../semantic-release@22.0.12_typescript@5.8.3/node_modules/semantic-release/bin/semantic-release.js" $args
  }
  $ret=$LASTEXITCODE
}
$env:NODE_PATH=$env_node_path
exit $ret
